    private Map<String, NUIForm> nuiFormCache = new HashMap<>();

    public EntryAnalyticResult analyseEntry(String apname,String path, int sheetIndex, int keyDomainId, int nodeId, boolean noTitle, User user, EntryNodeNLinkAnalyser.AnalyticPolicy policy, EntryAnalyticResult result) {
        if(result == null) result = new EntryAnalyticResult();

        Account ap = Account.getInstance(apname);
        Set<Integer> noDeleteDataWhenDeleteFields = ap.getNoDeleteDataWhenDeleteField().get(apname);

        //I'm not sure, I think it is for compatibility with previous version.
        Set<Integer> generatedToNewSheetFields = ap.getSubtableFieldsGeneratedToNewSheet().get(apname);

        String formPathSheet = path + "/" + sheetIndex;

        NUIForm form = nuiFormCache.get(formPathSheet);

        if(form == null) {
            form = AppManager.getFormPage(apname, path, sheetIndex);
            nuiFormCache.put(formPathSheet, form);
        }

        List<Integer> allFields = new ArrayList<>();
        Map<Integer, Set<Integer>> subtableKeyNRootNodeIds = new HashMap<>();   //domaind : nodeId

        Map<CellLocation, CellInfo> fields = form.getFields();

        //Only used for 1 entry analysis, a title for multi-entries is often special or need to know the number of entries after analysis.
        if(!noTitle) addTitle(result, form, nodeId, user, 1);

        BDBWorker worker = new BDBWorker(apname);
        worker.setWhoami("Entry Analysis "+ (user!=null?user.getUserId():""));

        String rootNodeValue = "";

        try {
            for (Map.Entry<CellLocation, CellInfo> f : fields.entrySet()) {
                CellLocation loc = f.getKey();
                CellInfo info = f.getValue();
                if (info.getDomainId() == keyDomainId) continue;   //skip self

                //processing all fields
                allFields.add(info.getDomainId());    //all domains in the form

                //processing subtable keys
                //nuiv2
                Integer subtableKey=form.getSubtableKey(loc);
                if (subtableKey != null) {
                    allFields.add(subtableKey); //implied subtable root domain in the form
                    if (keyDomainId != subtableKey.intValue()) {
                        subtableKeyNRootNodeIds.put(subtableKey, new LinkedHashSet<>());//make sure node id in order
                    }
                }
                //nuiv1
                else {
                    if (form.isFirstTableCell(loc)) {
                        subtableKeyNRootNodeIds.put(info.getDomainId(), new LinkedHashSet<>());//make sure node id in order
                    }
                }
            }
            //get subtable root domains' nodeId
            for (Map.Entry<Integer, Set<Integer>> e : subtableKeyNRootNodeIds.entrySet()) {
                int subtableKey = e.getKey();
                /*
                    for now we do not think records referenced by reference subtables should be deleted, see response to customer
                    This is currently the correct and must-have behavior. Reference subtables like this describe references to a record using a subtable.
                    It would result in unintended deletion if the referred to record is also deleted.

                    For example, if an item has a main vendor and a secondary vendor, we can create a reference subtable on vendor sheet to list items that this vendor sells.
                    If the secondary vendor is deleted from the database, the item itself should not be deleted.
                */

                int subtableParentAlias = form.getSubtableParentAlias(subtableKey);
                Set<Integer> subtableRootNodeIds = e.getValue();

                NodeSource ns;
                if(policy == EntryNodeNLinkAnalyser.AnalyticPolicy.DELETE_SUBTABLE_RECORD_PLUS_REFERENCES && subtableParentAlias!= Const.NODOMAIN){
                    ns = worker.getLinkedNodes(subtableParentAlias, nodeId, subtableKey);
                }
                else{
                    ns = worker.getLinkedNodes(keyDomainId, nodeId, subtableKey);
                }
                SDBNode node;
                while ((node = ns.next()) != null) {
                    subtableRootNodeIds.add(node.getId());
                }
            }


            //Analytic Policy
            if (policy == EntryNodeNLinkAnalyser.AnalyticPolicy.DELETE_SUBTABLE_RECORD || policy == EntryNodeNLinkAnalyser.AnalyticPolicy.DELETE_SUBTABLE_RECORD_PLUS_REFERENCES || policy == EntryNodeNLinkAnalyser.AnalyticPolicy.TEMPLATE_COPY || policy == EntryNodeNLinkAnalyser.AnalyticPolicy.MOVE_DATABASE) {

                //process subtable fields first
                for (Map.Entry<Integer, Set<Integer>> e : subtableKeyNRootNodeIds.entrySet()) {
                    int subtableKey = e.getKey();
                    Set<Integer> subtableRootNodeIds = e.getValue();
                    if (subtableRootNodeIds.size() == 0) continue;

                    for (int subtableRootNodeId : subtableRootNodeIds) {
                        if (generatedToNewSheetFields != null) {
                            for (Integer d : generatedToNewSheetFields) { //custom subtable fields
                                if (d == subtableKey) continue;
                                NodeSource ns = worker.getLinkedNodes(subtableKey, subtableRootNodeId, d);
                                SDBNode node;
                                if ((node = ns.next()) != null) {
                                    if (noDeleteDataWhenDeleteFields.contains(d)) {
                                        recordLinkInfo(result, subtableKey, subtableRootNodeId, d, node.getId());
                                    } else {
                                        recordLinkInfo(result, subtableKey, subtableRootNodeId, d, node.getId());
                                        recordNodeInfo(result, d, node.getId(), node.getValue());
                                    }
                                }
                            }
                        }

                        for (Integer d : allFields) { //subtable fields
                            if (d == subtableKey) continue;
                            NodeSource ns = worker.getLinkedNodes(subtableKey, subtableRootNodeId, d);
                            SDBNode node;
                            if ((node = ns.next()) != null) {
                                if (noDeleteDataWhenDeleteFields.contains(d) && policy != EntryNodeNLinkAnalyser.AnalyticPolicy.TEMPLATE_COPY) {
                                    recordLinkInfo(result, subtableKey, subtableRootNodeId, d, node.getId());
                                } else if(policy == EntryNodeNLinkAnalyser.AnalyticPolicy.TEMPLATE_COPY) {
                                    int realParentDomainId = Account.getInstance(apname).resolveAlias(d);
                                    if(form.getField(d).getAttribute("usrref") != null) {
                                        recordLinkInfo(result, subtableKey, subtableRootNodeId, d, 0);
                                    } else {
                                        recordLinkInfo(result, subtableKey, subtableRootNodeId, d, node.getId());
                                        if(realParentDomainId > 0) {
                                            recordNodeInfo(result, realParentDomainId, node.getId(), node.getValue());
                                        } else {
                                            recordNodeInfo(result, d, node.getId(), node.getValue());
                                        }
                                    }
                                } else {
                                    recordLinkInfo(result, subtableKey, subtableRootNodeId, d, node.getId());
                                    recordNodeInfo(result, d, node.getId(), node.getValue());
                                }
                            }
                        }
                    }
                }

                //process form fields and subtable root fields
                for (Integer d : allFields) {
                    if (d == keyDomainId) continue;

                    int subtableParentAlias = form.getSubtableParentAlias(d);
                    NodeSource ns;
                    if(policy == EntryNodeNLinkAnalyser.AnalyticPolicy.DELETE_SUBTABLE_RECORD_PLUS_REFERENCES && subtableParentAlias!=Const.NODOMAIN){
                        ns = worker.getLinkedNodes(subtableParentAlias, nodeId, d);
                    }
                    else{
                        ns = worker.getLinkedNodes(keyDomainId, nodeId, d);
                    }

                    SDBNode node;
                    while ((node = ns.next()) != null) {

                        //processing subtable roots
                        if (subtableKeyNRootNodeIds.containsKey(d)) {
                            //for referential integrity, when subtable is a form in another sheet, it should be deleted simultaneously
                            //for issue 01086, we don't delete such subtable data which is in other sheet even the delete setting is "Both form and subtable entries"
                            //so we can't delete this entry.

                            //UPDATE 2014/6/11 ameritek issue by support
                            //since the deletion policy states that the subtable entry should be deleted, we should delete it even when it's a whole entry in another form
                            recordLinkInfo(result, keyDomainId, nodeId, d, node.getId());

                            //don't delete users when they are subtable root, this is probably a user group sheet nuiv1
                            if (d== DConst.USER_USERID_EMAIL){}
                            //in other cases, delete subtable root node
                            else{
                                if(policy == EntryNodeNLinkAnalyser.AnalyticPolicy.TEMPLATE_COPY) {
                                    int realParentDomainId = Account.getInstance(apname).resolveAlias(d);
                                    recordNodeInfo(result, d, node.getId(), node.getValue());
                                } else {
                                    recordNodeInfo(result, d, node.getId(), node.getValue());
                                }
                            }
                        }

                        //other fields
                        else {
                            if (noDeleteDataWhenDeleteFields.contains(d) && policy != EntryNodeNLinkAnalyser.AnalyticPolicy.TEMPLATE_COPY) {
                                recordLinkInfo(result, keyDomainId, nodeId, d, node.getId());
                            } else if(policy == EntryNodeNLinkAnalyser.AnalyticPolicy.TEMPLATE_COPY) {
                                int realParentDomainId = Account.getInstance(apname).resolveAlias(d);
                                if(form.getField(d).getAttribute("usrref") != null) {
                                    recordLinkInfo(result, keyDomainId, nodeId, d, 0);
                                } else {
                                    recordLinkInfo(result, keyDomainId, nodeId, d, node.getId());
                                    if(realParentDomainId > 0) {
                                        recordNodeInfo(result, realParentDomainId, node.getId(), node.getValue());
                                    } else {
                                        recordNodeInfo(result, d, node.getId(), node.getValue());
                                    }
                                }
                            } else {
                                recordLinkInfo(result, keyDomainId, nodeId, d, node.getId());
                                recordNodeInfo(result, d, node.getId(), node.getValue());
                            }
                        }
                    }
                }
            }

            //Analyse form fields only
            else {
                //process form fields
                for (Integer d : allFields) {
                    if (d == keyDomainId) continue;
                    NodeSource ns = worker.getLinkedNodes(keyDomainId, nodeId, d);
                    SDBNode node;
                    while ((node = ns.next()) != null) {
                        if (subtableKeyNRootNodeIds.containsKey(d)) { //skip subtable root
                            continue;
                        } else {
                            if (noDeleteDataWhenDeleteFields.contains(d)) {
                                recordLinkInfo(result, keyDomainId, nodeId, d, node.getId());
                            } else {
                                recordLinkInfo(result, keyDomainId, nodeId, d, node.getId());
                                recordNodeInfo(result, d, node.getId(), node.getValue());
                            }
                        }
                    }
                }
            }

            // Mark procHistory for issue #05322
            if(policy == EntryNodeNLinkAnalyser.AnalyticPolicy.MOVE_DATABASE) {
                //recordApproval(worker, keyDomainId, nodeId, result);
                //recordEmailConversation(worker, keyDomainId, nodeId, result);
            }
            //procHistory(worker, domainId, nodeId, delRecord, deleteSet, unlinkSet);

            if(policy != EntryNodeNLinkAnalyser.AnalyticPolicy.TEMPLATE_COPY) {
                recordComment(worker, keyDomainId, nodeId, result);
                recordCreateInfo(worker, keyDomainId, nodeId, result);
            }

            //process root node
            SDBNode rootNode = worker.getNode(keyDomainId, nodeId);
            if (rootNode != null) {
                rootNodeValue = rootNode.getValue();
                recordNodeInfo(result, keyDomainId, nodeId, rootNodeValue);
            }

        } catch (Exception e) {
            //return "E";
            e.printStackTrace();
            result.getRecord().add(0, new String[]{"E"});
            return result;
        } finally {
            worker.commit();
        }


        return result;
    }

    private void addTitle(EntryAnalyticResult result, NUIForm form, int nodeId, User user, int numberOfEntries) {
        List<String[]> record = result.getRecord();
        String[] s = new String[8];
        s[0] = "N";
        s[1] = form.getApname();
        s[2] = form.getPath();
        s[3] = form.getSheetIndex();
        s[4] = form.getRealname();
        String date = LocalDateTime.now().format(Const.StdDateTimeFormatter);
        s[5] = user.getUserId();
        s[6] = date;
        s[7] = String.valueOf(numberOfEntries);
        record.add(s);
        String[] s2 = new String[2];
        s2[0] = "RootNodes";
        s2[1] = String.valueOf(nodeId);
        record.add(s2);
    }

    private void recordLinkInfo(EntryAnalyticResult result, int domainId, int nodeId, int domainId2, int nodeId2) {
        Set<Integer[]> linkSet = result.getLinkSet();
        List<String[]> record = result.getRecord();
        Integer[] unlinkId = new Integer[]{domainId, nodeId, domainId2, nodeId2};
        linkSet.add(unlinkId);
        String[] s = new String[5];
        s[0] = "UN";
        s[1] = String.valueOf(domainId);
        s[2] = String.valueOf(nodeId);
        s[3] = String.valueOf(domainId2);
        s[4] = String.valueOf(nodeId2);
        record.add(s);
    }

    private void recordNodeInfo(EntryAnalyticResult result, int domainId, int nodeId, String value) {
        Set<Integer[]> nodeSet = result.getNodeSet();
        List<String[]> record = result.getRecord();
        Integer[] nodeInfo = new Integer[]{domainId, nodeId};
        nodeSet.add(nodeInfo);
        String[] s = new String[4];
        s[0] = "DN";
        s[1] = String.valueOf(domainId);
        s[2] = String.valueOf(nodeId);
        s[3] = String.valueOf(value);
        record.add(s);

    }

    private void recordComment(BDBWorker worker, int domainId, int nodeId, EntryAnalyticResult result) {
        int[] commentDomain = new int[]{
                DConst.COMMENT_TIMESTAMP, DConst.COMMENT_PATH, DConst.COMMENT_SHEET,
                DConst.COMMENT_USERID, DConst.COMMENT_USERNAME, DConst.COMMENT_CONTENT,
                DConst.COMMENT_ATTACHMENT, DConst.COMMENT_STATUS, DConst.COMMENT_KEY,
                DConst.COMMENT_COUNT, DConst.COMMENT_IMAGE
        };
        NodeSource ns, ns2;
        ns = worker.getLinkedNodes(domainId, nodeId, commentDomain[0]);
        SDBNode node, node2;
        while ((node = ns.next()) != null) {
            recordLinkInfo(result, domainId, nodeId, commentDomain[0], node.getId());
            recordNodeInfo(result, commentDomain[0], node.getId(), node.getValue());
            for (int i = 1; i < commentDomain.length; i++) {
                ns2 = worker.getLinkedNodes(commentDomain[0], node.getId(), commentDomain[i]);
                while ((node2 = ns2.next()) != null) {
                    recordLinkInfo(result, commentDomain[0], node.getId(), commentDomain[i], node2.getId());
                    if (commentDomain[i] == DConst.COMMENT_CONTENT || commentDomain[i] == DConst.COMMENT_ATTACHMENT)
                        recordNodeInfo(result, commentDomain[i], node2.getId(), node2.getValue());
                    //System.out.println("comment delete:"+commentDomain[i]+"=>"+node2.getId());
                }
            }
        }

        ns = worker.getLinkedNodes(domainId, nodeId,  DConst.COMMENT_COUNT);
        while ((node = ns.next()) != null) {
            recordLinkInfo(result, domainId, nodeId, DConst.COMMENT_COUNT, node.getId());
        }
    }

    private void recordCreateInfo(BDBWorker worker, int domainId, int nodeId, EntryAnalyticResult result) {
        int[] createInfoDomain = new int[] {
                DConst.ENTRY_GUEST_USER, DConst.ENTRY_CREATE_DATE, DConst.ENTRY_ENTRY_MANAGER,
                DConst.ENTRY_ORIGINAL_CREATE_USER, DConst.ENTRY_NOTIFY_USERS, DConst.ENTRY_EXTERNAL_GUID,
                DConst.ENTRY_LOCKED, DConst.ENTRY_STAR
        };
        NodeSource ns;
        SDBNode node;
        for (int aCreateInfoDomain : createInfoDomain) {
            ns = worker.getLinkedNodes(domainId, nodeId, aCreateInfoDomain);
            while ((node = ns.next()) != null) {
                recordLinkInfo(result, domainId, nodeId, aCreateInfoDomain, node.getId());
                if (aCreateInfoDomain == DConst.ENTRY_CREATE_DATE || aCreateInfoDomain == DConst.ENTRY_EXTERNAL_GUID) {
                    recordNodeInfo(result, aCreateInfoDomain, node.getId(), node.getValue());
                }
            }
        }
    }
    public void saveResultToCSVFormat(EntryAnalyticResult result, Path saveTo, boolean append) {
        try {
            if(saveTo.getParent() != null) Files.createDirectories(saveTo.getParent());
            List<String[]> record = result.getRecord();
            try (FileWriter fw = new FileWriter(saveTo.toFile(), append); CSVCreator c = new CSVCreator(fw)) {
                c.writeAll(record);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
    private void recordAutoGenerateInfo(BDBWorker worker, final EntryAnalyticResult result) {
        SDBQuery q = new SDBQueryFull(worker);
        q.go(DConst.SYS_AUTOINCR_NAME);
        SDBNode autoIncrNameNode;
        while((autoIncrNameNode = q.next()) != null) {
            int autoIncrNameNodeId = autoIncrNameNode.getId();
            recordNodeInfo(result, DConst.SYS_AUTOINCR_NAME, autoIncrNameNodeId, autoIncrNameNode.getValue());
            NodeSource ns = worker.getLinkedNodes(DConst.SYS_AUTOINCR_NAME, autoIncrNameNodeId, DConst.SYS_AUTOINCR_VALUE);
            SDBNode autoIncrValueNode;
            while((autoIncrValueNode = ns.next()) != null) {
                recordLinkInfo(result, DConst.SYS_AUTOINCR_NAME, autoIncrNameNodeId, DConst.SYS_AUTOINCR_VALUE, autoIncrValueNode.getId());
                recordNodeInfo(result, DConst.SYS_AUTOINCR_VALUE, autoIncrValueNode.getId(), autoIncrValueNode.getValue());
            }
        }

    }
    private void recordPersonalView(BDBWorker worker, int userEmailId, final EntryAnalyticResult result) {
        NodeSource ns = worker.getLinkedNodes(DConst.USER_USERID_EMAIL, userEmailId, DConst.SAVED_QUERY_NAME);
        SDBNode node = null;
        while ((node = ns.next() ) != null) {
            int queryNameId = node.getId();
            recordLinkInfo(result, DConst.USER_USERID_EMAIL, userEmailId, DConst.SAVED_QUERY_NAME, queryNameId);
            recordNodeInfo(result, DConst.SAVED_QUERY_NAME, queryNameId, node.getValue());
            NodeSource queryInfoNodeSource = worker.getLinkedNodes(DConst.SAVED_QUERY_NAME, queryNameId, DConst.SAVED_QUERY_URL);
            SDBNode queryInfoNode = null;
            while ((queryInfoNode = queryInfoNodeSource.next()) != null) {
                recordLinkInfo(result, DConst.SAVED_QUERY_NAME, queryNameId, DConst.SAVED_QUERY_URL, queryInfoNode.getId());
            }
            queryInfoNodeSource = worker.getLinkedNodes(DConst.SAVED_QUERY_NAME, queryNameId, DConst.SAVED_QUERY_STRING);
            while ((queryInfoNode = queryInfoNodeSource.next()) != null) {
                recordLinkInfo(result, DConst.SAVED_QUERY_NAME, queryNameId, DConst.SAVED_QUERY_STRING, queryInfoNode.getId());
                recordNodeInfo(result, DConst.SAVED_QUERY_STRING, queryInfoNode.getId(), queryInfoNode.getValue());
            }
        }
    }
    private void recordPreference(BDBWorker worker, int userEmailId, final EntryAnalyticResult result) {
        NodeSource ns = worker.getLinkedNodes(DConst.USER_USERID_EMAIL, userEmailId, DConst.SAVED_USER_PREFERENCE);
        SDBNode node;
        while ((node = ns.next() ) != null) {
            recordLinkInfo(result, DConst.USER_USERID_EMAIL, userEmailId, DConst.SAVED_USER_PREFERENCE, node.getId());
            recordNodeInfo(result, DConst.SAVED_QUERY_NAME, node.getId(), node.getValue());
        }
    }
    private void recordTask(BDBWorker worker, final EntryAnalyticResult result) {
        SDBQuery q = new SDBQueryFull(worker);
        q.go(DConst.TASK_KEY);
        SDBNode n = null;
        while((n = q.next()) != null) {
            int taskId = n.getId();
            String taskValue = n.getValue();
            recordNodeInfo(result, DConst.TASK_KEY, taskId, taskValue);
            TASK_DOMAINS.forEach(domain -> {
                NodeSource ns = worker.getLinkedNodes(DConst.TASK_KEY, taskId ,domain);
                SDBNode node = null;
                while((node = ns.next()) != null) {
                    recordLinkInfo(result, DConst.TASK_KEY, taskId, domain, node.getId());
                    if(domain != DConst.TASK_PATHSHEET && domain != DConst.TASK_TYPE && domain != DConst.TASK_STATUS) recordNodeInfo(result, domain, node.getId(), node.getValue());
                }
            });
        }
    }
