  public void _jspService(final javax.servlet.http.HttpServletRequest request, final javax.servlet.http.HttpServletResponse response)
      throws java.io.IOException, javax.servlet.ServletException {

    final java.lang.String _jspx_method = request.getMethod();
    if (!"GET".equals(_jspx_method) && !"POST".equals(_jspx_method) && !"HEAD".equals(_jspx_method) && !javax.servlet.DispatcherType.ERROR.equals(request.getDispatcherType())) {
      response.sendError(HttpServletResponse.SC_METHOD_NOT_ALLOWED, "JSPs only permit GET POST or HEAD");
      return;
    }

    final javax.servlet.jsp.PageContext pageContext;
    javax.servlet.http.HttpSession session = null;
    final javax.servlet.ServletContext application;
    final javax.servlet.ServletConfig config;
    javax.servlet.jsp.JspWriter out = null;
    final java.lang.Object page = this;
    javax.servlet.jsp.JspWriter _jspx_out = null;
    javax.servlet.jsp.PageContext _jspx_page_context = null;


    try {
      response.setContentType("text/html");
      pageContext = _jspxFactory.getPageContext(this, request, response,
      			null, true, 8192, true);
      _jspx_page_context = pageContext;
      application = pageContext.getServletContext();
      config = pageContext.getServletConfig();
      session = pageContext.getSession();
      out = pageContext.getOut();
      _jspx_out = out;


    String apname="DelivereeTH2";
    User user=(User)session.getAttribute("USER");
    Path filePath = Paths.get("cust", "data", apname, "tmp", "DBBACKUP_" + Instant.now().toEpochMilli() + "_" + user.getUserId() + ".csv");
    EntryAnalyticResult result = new EntryAnalyticResult();
    Map<String, App> frontInst = AppManager.getInstalledApplications(apname);
    for (App ins : frontInst.values()) {

        String path = ins.getPath();
        int count = 0;

        Map<String, String> pathFormNames = AppManager.getFormNamesInPath(apname, ins.getPath(), user);
        for (Map.Entry<String, String> e : pathFormNames.entrySet()) {
            String[] sec = e.getKey().split("_");

            int si = Encoder.parseInt(sec[0], -1);
            String formPathSheet = path + "/" + si;
            NUIForm formPage = nuiFormCache.get(formPathSheet);

            if(formPage == null) {
                formPage = AppManager.getFormPage(apname, path, si);
                nuiFormCache.put(formPathSheet, formPage);
            }

            APIQuery aq = new APIQuery(apname, path, si);
            aq.setIfIgnoreFixedFilter(true);
            APIResultsFull results = aq.getAPIResultsFull();

            for(APIEntry entry :results){
                result = analyseEntry(apname,path, si, formPage.getRootDomainId(), entry.getRootNodeId(), true, user, EntryNodeNLinkAnalyser.AnalyticPolicy.MOVE_DATABASE, result);
                count++;
                if(count == 1000) {
                    saveResultToCSVFormat(result, filePath, true);
                    count = 0;
                    result = new EntryAnalyticResult();
                }
            }
        }
    }

    saveResultToCSVFormat(result, filePath, true);

    result = new EntryAnalyticResult();
    BDBWorker taskWorker = new BDBWorker(apname);
    taskWorker.setWhoami("EntryNodeNLinkAnalyser createApAnalyserReport taskWorker :" + apname);
    try {
        recordTask(taskWorker, result);
    } catch (Exception e) {
        e.printStackTrace();
    } finally {
        taskWorker.commit();
    }

    saveResultToCSVFormat(result, filePath, true);
//    result = new EntryAnalyticResult();
//
//    BDBWorker notificationWorker = new BDBWorker(apname);
//    taskWorker.setWhoami("EntryNodeNLinkAnalyser createApAnalyserReport notificationWorker :" + apname);
//    try {
//        recordNotification(notificationWorker, result);
//    } catch (Exception e) {
//        e.printStackTrace();
//    } finally {
//        notificationWorker.commit();
//    }

    saveResultToCSVFormat(result, filePath, true);

    result = new EntryAnalyticResult();

    BDBWorker autoGenInfoWorker = new BDBWorker(apname);
    taskWorker.setWhoami("EntryNodeNLinkAnalyser createApAnalyserReport autoGenInfoWorker :" + apname);
    try {
        recordAutoGenerateInfo(autoGenInfoWorker, result);
    } catch (Exception e) {
        e.printStackTrace();
    } finally {
        autoGenInfoWorker.commit();
    }

    saveResultToCSVFormat(result, filePath, true);

    result = new EntryAnalyticResult();

    Account ap = Account.getInstance(apname);
    Set<Integer> extraHandlingDomain = ap.getNoDeleteDataWhenDeleteField().get(apname);
    extraHandlingDomain.addAll(NEED_EXTRA_HANDLING_DOMAINS);

    for(int field : extraHandlingDomain) {
        BDBWorker worker = new BDBWorker(apname);
        worker.setWhoami("EntryNodeNLinkAnalyser createApAnalyserReport " + ap + ": " + field);
        try {
            SDBQuery q = new SDBQueryFull(worker);
            q.go(field);
            SDBNode n;
            while((n = q.next()) != null) {

                switch (field) {
                    case DConst.USER_USERID_EMAIL:
                        recordPersonalView(worker, n.getId(), result);
                        recordPreference(worker, n.getId(), result);
                        break;
                    case DConst.SAVED_QUERY_URL:
                        String[] values = n.getValue().split("/");
                        recordNodeInfo(result, field, n.getId(), "/" + values[1] + "/" + values[2]);
                        break;
                    default:
                        recordNodeInfo(result, field, n.getId(), n.getValue());
                        break;
                }
                if(field == DConst.USER_USERID_EMAIL) {
                    recordPersonalView(worker, n.getId(), result);
                }

            }
        } catch (Exception e) {
            e.printStackTrace();
        } finally {
            worker.commit();
        }
    }

    saveResultToCSVFormat(result, filePath, true);



    } catch (java.lang.Throwable t) {
      if (!(t instanceof javax.servlet.jsp.SkipPageException)){
        out = _jspx_out;
        if (out != null && out.getBufferSize() != 0)
          try {
            if (response.isCommitted()) {
              out.flush();
            } else {
              out.clearBuffer();
            }
          } catch (java.io.IOException e) {}
        if (_jspx_page_context != null) _jspx_page_context.handlePageException(t);
        else throw new ServletException(t);
      }
    } finally {
      _jspxFactory.releasePageContext(_jspx_page_context);
    }
  }
